   215→Http::HeaderTransforms HeaderParser::getHeaderTransforms(const StreamInfo::StreamInfo& stream_info,
   216→                                                         bool do_formatting) const {
   217→  Http::HeaderTransforms transforms;
   218→
   219→  for (const auto& [key, entry] : headers_to_add_) {
   220→    if (do_formatting) {
   221→      const std::string value = entry->formatter_->formatWithContext({}, stream_info);
   222→      if (!value.empty() || entry->add_if_empty_) {
   223→        switch (entry->append_action_) {
   224→        case HeaderValueOption::APPEND_IF_EXISTS_OR_ADD:
   225→          transforms.headers_to_append_or_add.push_back({key, value});
   226→          break;
   227→        case HeaderValueOption::OVERWRITE_IF_EXISTS_OR_ADD:
   228→          transforms.headers_to_overwrite_or_add.push_back({key, value});
   229→          break;
   230→        case HeaderValueOption::ADD_IF_ABSENT:
   231→          transforms.headers_to_add_if_absent.push_back({key, value});
   232→          break;
   233→        default:
   234→          break;
   235→        }
   236→      }
   237→    } else {
   238→      switch (entry->append_action_) {
   239→      case HeaderValueOption::APPEND_IF_EXISTS_OR_ADD:
   240→        transforms.headers_to_append_or_add.push_back({key, entry->original_value_});
   241→        break;
   242→      case HeaderValueOption::OVERWRITE_IF_EXISTS_OR_ADD:
   243→        transforms.headers_to_overwrite_or_add.push_back({key, entry->original_value_});
   244→        break;
   245→      case HeaderValueOption::ADD_IF_ABSENT:
   246→        transforms.headers_to_add_if_absent.push_back({key, entry->original_value_});
   247→        break;
   248→      default:
   249→        break;
   250→      }
   251→    }
   252→  }
   253→
