   924→  // Only do base state setting on the initial call. Subsequent calls for filtering do not touch
   925→  // the base state.
   926→  ENVOY_STREAM_LOG(trace, "commonEncodePrefix end_stream: {}, isHalfCloseEnabled: {}", *this,
   927→                   end_stream, filter_manager_callbacks_.isHalfCloseEnabled());
   928→  if (filter == nullptr) {
   929→    if (end_stream) {
   930→      ASSERT(!state_.observed_encode_end_stream_);
   931→      state_.observed_encode_end_stream_ = true;
   932→
   933→      // When half close semantics are disabled, receiving end stream from the upstream causes
   934→      // decoder filter to stop, as neither filters nor upstream is interested in downstream data.
   935→      // half close is enabled in case tcp proxying is done with http1 encoder. In this case, we
   936→      // should not stop decoder filter chain when end_stream is true, as it will cause any data
   937→      // sent in the upstream direction to be
   938→      // dropped.
   939→      if (!filter_manager_callbacks_.isHalfCloseEnabled()) {
   940→        state_.decoder_filter_chain_aborted_ = true;
   941→      }
