   944→  }
   945→
   946→  if (filter_iteration_start_state == FilterIterationStartState::CanStartFromCurrent &&
   947→      (*(filter->entry()))->iterate_from_current_filter_) {
   948→    // The filter iteration has been stopped for all frame types, and now the iteration continues.
   949→    // The current filter's encoding callback has not be called. Call it now.
   950→    return filter->entry();
   951→  }
